import AVFoundation
import AppKit
import ApplicationServices
import Foundation
import Observation

@MainActor
@Observable
final class PermissionsService {
    enum Status: Sendable, Equatable {
        case granted
        case denied
        case notDetermined
        case unknown

        var label: String {
            switch self {
            case .granted: return String(localized: "Granted")
            case .denied: return String(localized: "Missing")
            case .notDetermined: return String(localized: "Not requested")
            case .unknown: return String(localized: "Unknown")
            }
        }
    }

    private(set) var microphoneStatus: Status = .unknown
    private(set) var accessibilityStatus: Status = .unknown

    init() {
        refresh()
    }

    func refresh() {
        microphoneStatus = currentMicStatus()
        accessibilityStatus = AXIsProcessTrusted() ? .granted : .denied
    }

    func requestMicrophone() async {
        let granted = await AVCaptureDevice.requestAccess(for: .audio)
        microphoneStatus = granted ? .granted : .denied
    }

    func openMicrophoneSettings() {
        if let url = URL(string: "x-apple.systempreferences:com.apple.preference.security?Privacy_Microphone") {
            NSWorkspace.shared.open(url)
        }
    }

    func openAccessibilitySettings() {
        if let url = URL(string: "x-apple.systempreferences:com.apple.preference.security?Privacy_Accessibility") {
            NSWorkspace.shared.open(url)
        }
    }

    private func currentMicStatus() -> Status {
        switch AVCaptureDevice.authorizationStatus(for: .audio) {
        case .authorized: return .granted
        case .denied, .restricted: return .denied
        case .notDetermined: return .notDetermined
        @unknown default: return .unknown
        }
    }
}

import AppKit
import SwiftUI

@MainActor
final class SettingsWindowController: NSObject, NSWindowDelegate {
    private weak var container: AppContainer?
    private var window: NSWindow?

    init(container: AppContainer) {
        self.container = container
        super.init()
    }

    func show() {
        if let window {
            NSApp.activate(ignoringOtherApps: true)
            window.makeKeyAndOrderFront(nil)
            return
        }
        guard let container else { return }
        let hosting = NSHostingController(rootView: SettingsScene().environment(container))
        let size = NSSize(width: 580, height: 560)
        hosting.preferredContentSize = size

        let styleMask: NSWindow.StyleMask = [.titled, .closable, .miniaturizable]
        let window = NSWindow(
            contentRect: NSRect(origin: .zero, size: size),
            styleMask: styleMask,
            backing: .buffered,
            defer: false
        )
        window.title = String(localized: "ThinkAloud Settings")
        window.contentViewController = hosting
        window.isReleasedWhenClosed = false
        window.center()
        window.delegate = self

        NSApp.activate(ignoringOtherApps: true)
        window.makeKeyAndOrderFront(nil)
        self.window = window
    }

    nonisolated func windowWillClose(_ notification: Notification) {
        MainActor.assumeIsolated {
            self.window = nil
        }
    }
}

