167	    private func scheduleIdleEvictionIfNeeded() {
168	        idleEvictionTask?.cancel()
169	        guard let timeout = idleTimeout.seconds else { return }
170	        let runtime = runtimeRef
171	        let activityAt = lastActivityAt
172	        idleEvictionTask = Task { @MainActor [weak self] in
173	            // Sleep until the timeout has elapsed since the recorded activity.
174	            let now = Date()
175	            let elapsed = now.timeIntervalSince(activityAt)
176	            let remaining = max(timeout - elapsed, 0)
177	            try? await Task.sleep(nanoseconds: UInt64(remaining * 1_000_000_000))
178	            if Task.isCancelled { return }
179	            guard let self else { return }
180	            // Confirm still idle: lastActivityAt must not have moved.
181	            if self.lastActivityAt != activityAt { return }
182	            // Only unload if currently ready.
183	            if case .ready = await runtime.status() {
