210	    /// for non-active profiles it spins up a transient runtime, fetches, then unloads its weights.
211	    func downloadProfile(_ profile: ModelProfile) async throws {
212	        if profile == self.profile {
213	            // Active profile: reuse the live runtime so its weights stay loaded afterwards.
214	            let poll = startProfileDownloadPolling(profile: profile, runtime: runtimeRef)
215	            defer {
216	                poll.cancel()
217	                profileDownloadStatus[profile] = nil
218	            }
219	            try await runtimeRef.preload()
220	            return
221	        }
222	        let transient = ASRRuntimeFactory.make(profile: profile, cacheDirectory: modelsDirectory)
