235	    /// ready/failed; the caller also cancels it via `defer` once `preload()` returns.
236	    private func startProfileDownloadPolling(profile: ModelProfile, runtime: any ASRRuntime) -> Task<Void, Never> {
237	        Task { @MainActor [weak self] in
238	            while !Task.isCancelled {
239	                let s = await runtime.status()
240	                if Task.isCancelled { return }
241	                self?.profileDownloadStatus[profile] = s
242	                if case .ready = s { return }
243	                if case .failed = s { return }
244	                try? await Task.sleep(nanoseconds: 250_000_000)
245	            }
246	        }
247	    }
