249	    /// Removes a profile's snapshot directory and its parallel HF blob cache. If it's the
250	    /// currently-selected profile, the active runtime is unloaded first to release file handles.
251	    func removeProfile(_ profile: ModelProfile) throws {
252	        if profile == self.profile {
253	            unloadNow()
254	        }
255	        let snapshot = snapshotURL(for: profile)
256	        if FileManager.default.fileExists(atPath: snapshot.path) {
257	            try FileManager.default.removeItem(at: snapshot)
258	        }
259	        // Also clear the HF-style cache if it's still around (parallel layout from huggingface-swift).
260	        let parts = profile.modelID.split(separator: "/")
261	        if parts.count == 2 {
262	            let hfFolder = "models--\(parts[0])--\(parts[1])"
263	            let hfDir = modelsDirectory.appendingPathComponent(hfFolder)
264	            if FileManager.default.fileExists(atPath: hfDir.path) {
265	                try? FileManager.default.removeItem(at: hfDir)
266	            }
267	        }
268	    }
