270	    /// mlx-audio-swift loads from `<models>/mlx-audio/<id>/` (flat copies). The downloader
271	    /// also leaves a parallel HF-style cache at `<models>/models--org--repo/` (snapshots +
272	    /// blobs). Once mlx-audio has the flat copy it never reads the HF cache again, so the
273	    /// HF directory is redundant and can be safely removed to reclaim ~half the disk usage.
274	    @discardableResult
275	    func pruneRedundantHFCache() -> Int64 {
276	        let fm = FileManager.default
277	        var freed: Int64 = 0
278	        let entries = (try? fm.contentsOfDirectory(at: modelsDirectory, includingPropertiesForKeys: nil)) ?? []
279	        for url in entries where url.lastPathComponent.hasPrefix("models--") {
280	            let size = directorySize(url)
281	            do {
282	                try fm.removeItem(at: url)
283	                freed += size
284	                NSLog("ThinkAloud: pruned redundant HF cache \(url.lastPathComponent) freed=\(size)B")
285	            } catch {
286	                NSLog("ThinkAloud: failed to prune \(url.lastPathComponent): \(error)")
287	            }
288	        }
289	        return freed
290	    }
291	
292	    private func directorySize(_ url: URL) -> Int64 {
293	        let fm = FileManager.default
294	        guard let enumerator = fm.enumerator(at: url, includingPropertiesForKeys: [.totalFileAllocatedSizeKey, .fileSizeKey]) else { return 0 }
295	        var total: Int64 = 0
296	        for case let entry as URL in enumerator {
297	            let values = try? entry.resourceValues(forKeys: [.totalFileAllocatedSizeKey, .fileSizeKey])
298	            total += Int64(values?.totalFileAllocatedSize ?? values?.fileSize ?? 0)
299	        }
300	        return total
301	    }
302	
303	    func cacheSizeBytes() -> Int64 {
304	        let fm = FileManager.default
305	        guard let enumerator = fm.enumerator(at: modelsDirectory, includingPropertiesForKeys: [.fileSizeKey, .totalFileAllocatedSizeKey]) else {
306	            return 0
307	        }
308	        var total: Int64 = 0
309	        for case let url as URL in enumerator {
310	            let values = try? url.resourceValues(forKeys: [.totalFileAllocatedSizeKey, .fileSizeKey])
311	            total += Int64(values?.totalFileAllocatedSize ?? values?.fileSize ?? 0)
312	        }
313	        return total
314	    }
315	}
