import SwiftUI

struct ModelStep: View {
    @Environment(AppContainer.self) private var container

    var body: some View {
        ScrollView {
            VStack(alignment: .leading, spacing: 16) {
                OnboardingHeader(
                    title: "Choose a speech model",
                    subtitle: "Pick the model that fits your Mac. It downloads once and runs on-device. You can switch anytime in Settings."
                )

                VStack(spacing: 8) {
                    ForEach(ModelProfile.allCases) { profile in
                        modelRow(profile)
                    }
                }

                statusArea
            }
            .padding(32)
        }
    }

    private var manager: ModelManager { container.modelManager }

    // MARK: - Rows

    private func modelRow(_ profile: ModelProfile) -> some View {
        let isSelected = manager.profile == profile
        let downloaded = manager.isDownloaded(profile)
        return Button {
            // Avoid switching mid-download: the status poll tracks one runtime at a time.
            guard !manager.runtimeStatus.isLoading else { return }
            manager.setProfile(profile)
        } label: {
            HStack(alignment: .top, spacing: 12) {
                Image(systemName: isSelected ? "largecircle.fill.circle" : "circle")
                    .foregroundStyle(isSelected ? Color.accentColor : .secondary)
                    .imageScale(.large)
                VStack(alignment: .leading, spacing: 3) {
                    HStack(spacing: 6) {
                        Text(profile.displayName).font(.headline)
                        if downloaded {
                            Image(systemName: "checkmark.circle.fill")
                                .foregroundStyle(.green)
                                .imageScale(.small)
                                .help(String(localized: "Already downloaded"))
                        }
                    }
                    Text(profile.tagline)
                        .font(.callout)
                        .foregroundStyle(.secondary)
                        .fixedSize(horizontal: false, vertical: true)
                }
                Spacer(minLength: 8)
                Text(downloaded ? String(localized: "Downloaded") : profile.estimatedDownloadSize)
                    .font(.caption)
                    .foregroundStyle(.secondary)
            }
            .padding(12)
            .frame(maxWidth: .infinity, alignment: .leading)
            .background(
                RoundedRectangle(cornerRadius: 10)
                    .fill(isSelected ? Color.accentColor.opacity(0.12) : Color.quaternary.opacity(0.4))
            )
            .overlay(
                RoundedRectangle(cornerRadius: 10)
                    .strokeBorder(isSelected ? Color.accentColor : .clear, lineWidth: 1.5)
            )
        }
        .buttonStyle(.plain)
        .disabled(manager.runtimeStatus.isLoading)
    }

    // MARK: - Status / download

    @ViewBuilder
    private var statusArea: some View {
        let status = manager.runtimeStatus
        let downloaded = manager.isDownloaded(manager.profile)

        VStack(alignment: .leading, spacing: 10) {
            if status.isLoading {
                HStack {
                    StatusBadge(tone: status.badge, text: status.displayLabel)
                    Spacer()
                }
                if let progress = status.downloadProgress {
                    ProgressView(value: progress)
                } else {
                    ProgressView()
                }
            } else if status.isReady || downloaded {
                Label(String(localized: "Ready to use"), systemImage: "checkmark.circle.fill")
                    .foregroundStyle(.green)
            } else {
                Button {
                    manager.preloadNow()
                } label: {
                    Label(String(localized: "Download & load model"), systemImage: "arrow.down.circle")
                }
                .buttonStyle(.borderedProminent)

                Text("This downloads the selected model now so your first transcription is instant.")
                    .font(.caption)
                    .foregroundStyle(.secondary)
            }

            if let error = manager.lastError, case .failed = status {
                Text(error)
                    .font(.caption)
                    .foregroundStyle(.red)
                    .lineLimit(3)
            }

            if !(status.isReady || downloaded) {
                Button(String(localized: "Download later")) {
                    container.onboardingState.next()
                }
                .buttonStyle(.link)
                .padding(.top, 2)
            }
        }
        .padding(.top, 4)
    }
}

import SwiftUI

/// Root view of the onboarding window: progress dots on top, the current step in the
/// middle (animated when it changes), and a shared navigation bar at the bottom.
struct OnboardingScene: View {
    @Environment(AppContainer.self) private var container

    var body: some View {
        VStack(spacing: 0) {
            OnboardingStepIndicator(current: container.onboardingState.step)
                .padding(.top, 18)
                .padding(.bottom, 14)

            Divider()

            currentStep
                .frame(maxWidth: .infinity, maxHeight: .infinity)
                .id(container.onboardingState.step)
                .transition(.asymmetric(
                    insertion: .move(edge: .trailing).combined(with: .opacity),
                    removal: .move(edge: .leading).combined(with: .opacity)
                ))

            Divider()

            OnboardingNavBar()
                .padding(.horizontal, 20)
                .padding(.vertical, 14)
        }
        .frame(width: 640, height: 600)
        .animation(.easeInOut(duration: 0.25), value: container.onboardingState.step)
    }

    @ViewBuilder
    private var currentStep: some View {
        switch container.onboardingState.step {
        case .welcome: WelcomeStep()
        case .permissions: PermissionsStep()
        case .model: ModelStep()
        case .tutorial: TutorialStep()
        case .finish: FinishStep()
        }
    }
}

// MARK: - Progress indicator

/// Horizontal pill row; steps up to and including the current one are tinted, the active
/// one is elongated.
struct OnboardingStepIndicator: View {
    let current: OnboardingStep

    var body: some View {
        HStack(spacing: 8) {
            ForEach(OnboardingStep.allCases) { step in
                Capsule()
                    .fill(step.rawValue <= current.rawValue ? Color.accentColor : Color.secondary.opacity(0.25))
                    .frame(width: step == current ? 24 : 8, height: 8)
            }
        }
    }
}

// MARK: - Navigation bar

/// Shared bottom bar: Back (when applicable), a "Skip setup" link, and a primary
/// forward button whose label and enabled-state are step-aware.
struct OnboardingNavBar: View {
    @Environment(AppContainer.self) private var container

    var body: some View {
        HStack {
            if container.onboardingState.canGoBack {
                Button(String(localized: "Back")) {
                    container.onboardingState.back()
                }
            }
            Spacer()
            if !container.onboardingState.isLastStep {
                Button(String(localized: "Skip setup")) {
                    container.finishOnboarding()
                }
                .buttonStyle(.link)
            }
            Button(primaryTitle) { advance() }
                .keyboardShortcut(.defaultAction)
                .disabled(primaryDisabled)
        }
    }

    private var primaryTitle: String {
        switch container.onboardingState.step {
        case .welcome: return String(localized: "Get Started")
        case .finish: return String(localized: "Start Using ThinkAloud")
        default: return String(localized: "Continue")
        }
    }

    /// The only gated step is Model: you can't advance with "Continue" until the chosen
    /// model is on disk (or loaded). The Model step still offers its own "Download later"
    /// escape, and "Skip setup" is always available.
    private var primaryDisabled: Bool {
        guard container.onboardingState.step == .model else { return false }
        let manager = container.modelManager
        return !(manager.runtimeStatus.isReady || manager.isDownloaded(manager.profile))
    }

    private func advance() {
        if container.onboardingState.isLastStep {
            container.finishOnboarding()
        } else {
            container.onboardingState.next()
        }
    }
}

// MARK: - Shared step building blocks

/// Title + subtitle header used at the top of most steps.
struct OnboardingHeader: View {
    let title: LocalizedStringKey
    let subtitle: LocalizedStringKey

    var body: some View {
        VStack(alignment: .leading, spacing: 6) {
            Text(title).font(.title2.bold())
            Text(subtitle)
                .foregroundStyle(.secondary)
                .fixedSize(horizontal: false, vertical: true)
        }
    }
}

/// Icon + text bullet used on the Welcome step.
struct OnboardingFeatureRow: View {
    let icon: String
    let text: LocalizedStringKey

    var body: some View {
        HStack(alignment: .firstTextBaseline, spacing: 12) {
            Image(systemName: icon)
                .foregroundStyle(.tint)
                .frame(width: 22)
            Text(text)
                .fixedSize(horizontal: false, vertical: true)
            Spacer(minLength: 0)
        }
    }
}

/// Rounded container card matching the grouped-form look used elsewhere in the app.
struct OnboardingCard<Content: View>: View {
    @ViewBuilder var content: Content

    var body: some View {
        content
            .padding(16)
            .frame(maxWidth: .infinity, alignment: .leading)
            .background(.quaternary.opacity(0.5), in: RoundedRectangle(cornerRadius: 10))
    }
}

import AVFoundation
import AppKit
import ApplicationServices
import Foundation
import Observation

@MainActor
@Observable
final class PermissionsService {
    enum Status: Sendable, Equatable {
        case granted
        case denied
        case notDetermined
        case unknown

        var label: String {
            switch self {
            case .granted: return String(localized: "Granted")
            case .denied: return String(localized: "Missing")
            case .notDetermined: return String(localized: "Not requested")
            case .unknown: return String(localized: "Unknown")
            }
        }
    }

    private(set) var microphoneStatus: Status = .unknown
    private(set) var accessibilityStatus: Status = .unknown

    init() {
        refresh()
    }

    func refresh() {
        microphoneStatus = currentMicStatus()
        accessibilityStatus = AXIsProcessTrusted() ? .granted : .denied
    }

    func requestMicrophone() async {
        let granted = await AVCaptureDevice.requestAccess(for: .audio)
        microphoneStatus = granted ? .granted : .denied
    }

    func openMicrophoneSettings() {
        if let url = URL(string: "x-apple.systempreferences:com.apple.preference.security?Privacy_Microphone") {
            NSWorkspace.shared.open(url)
        }
    }

    /// Triggers macOS's own "grant Accessibility access" dialog and registers the app in the
    /// Accessibility list. Unlike microphone, there's no async grant callback — the user toggles
    /// it in System Settings — so callers should `refresh()` afterwards (e.g. on a poll / window
    /// focus) to pick up the change. Updates `accessibilityStatus` with the immediate result.
    func promptAccessibility() {
        let options = [kAXTrustedCheckOptionPrompt as String: true] as CFDictionary
        let trusted = AXIsProcessTrustedWithOptions(options)
        accessibilityStatus = trusted ? .granted : .denied
    }

    func openAccessibilitySettings() {
        if let url = URL(string: "x-apple.systempreferences:com.apple.preference.security?Privacy_Accessibility") {
            NSWorkspace.shared.open(url)
        }
    }

    private func currentMicStatus() -> Status {
        switch AVCaptureDevice.authorizationStatus(for: .audio) {
        case .authorized: return .granted
        case .denied, .restricted: return .denied
        case .notDetermined: return .notDetermined
        @unknown default: return .unknown
        }
    }
}

