struct PermissionsStep: View {
    @Environment(AppContainer.self) private var container

    /// Accessibility has no async grant callback — the user flips it in System Settings — so
    /// while this step is visible we re-check both permissions on a light timer to live-update
    /// the badges.
    @State private var pollTask: Task<Void, Never>?

    var body: some View {
        ScrollView {
            VStack(alignment: .leading, spacing: 18) {
                OnboardingHeader(
                    title: "Grant permissions",
                    subtitle: "ThinkAloud needs two macOS permissions. You can change these anytime in System Settings."
                )

                micCard
                accessibilityCard
            }
